module counter_8bit_updown(
    input clk,
    input reset,
    input up_down,
    output reg [7:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
        count <= 8'b00000000;
    else if (up_down)
        count <= count + 1;
    else
        count <= count - 1;
end

endmodule
